      }
 }
]

dynamicNameParams.description:
Provides possibility to generate file name using dynamic params.
How does it work:

Possible config:
```
 const file: string = "fileName_$PREV_START$_$NOW$.json";
 const dynamicNameParams: Array<IFtpDynamicNameParam> = [{
     name: "$PREV_START$",
     contextParam: {
         name: ContextParamsEnum.prevStart,
     }
  },{
     name: "$NOW$",
     contextParam: {
         name: ContextParamsEnum.now,
     }
  }];
```
In case `prevStart = 12345678945` and `now = 987654321` will generate:
```
 fileName_12345678945_987654321.json
```

IHttpRequestDataMapper.description:
Provides possibility to assemble request from given Action Flow Data Item.

Action Flow Data Item example:

```
{
    orderId: 1234,
    orderItem: {
        "itemId": 3456,
        "itemName": "Millennium Falcon",
        "count": 10,
        "amount": 5000
    }
}
```

